/**
 * @class Pronunciation Events
 * @description Typed Events for pronunciation (`{@link jibo.gl.PronunciationListener}.events`).
 * @extends jibo.gl.PronunciationEvents
 * @memberof jibo.gl
 */

    /**
     * generatedPronunciations Event
     * Pronunciations generated by the cloud model.
     * @name jibo.gl.PronunciationEvents#generatedPronunciations
     * @type {Event}
     * @readOnly
     */

    /**
     * heardPronunciations Event.
     * Pronunciations heard by acoustic example.
     * @name jibo.gl.PronunciationEvents#heardPronunciations
     * @type {Event}
     * @readOnly
     */

    /**
     * pronunciationError Event.
     * An error occured generating the pronunciation model or hearing the acoustic example.
     * @name jibo.gl.PronunciationEvents#pronunciationError
     * @type {Event}
     * @readOnly
     */

/**
 * @class PronunciationOptions
 * @description Options to pronounce.
 * @param {String} [word] Word to be pronounced.
 * @memberof jibo.gl
 */

    /**
     * Word to be pronounced.
     * @name jibo.gl.PronunciationOptions#word
     * @type {String}
     */

    /**
     * Action for listener to perform. Either `generateG2P` to generate
     * the model, or `collectExample` to collect acoustic example.
     * @default generateG2P
     * @name jibo.gl.PronunciationOptions#action
     * @type {String}
     */

    /**
     * ID used to identify listener in GLService.
     * @name jibo.gl.PronunciationListener#_listenerId
     * @type {String}
     */

/**
 * @class PronunciationListener
 * @description Listener for new pronunciations of words.
 * ```
 * () => {
 *   let pronounce = jibo.gl.createPronunciationListener({
 *     word: "Pronunciation"
 *   });
 *   pronounce.events.generatedPronunciations.on(function(data) {
 *     console.log("GENERATED PRONUN", data); // ["Pro nun see ay shun", "Proe nown see ae shun"]
 *     pronounce.collectExample();
 *   });
 *   pronounce.events.heardPronunciations.on(function(data) {
 *     console.log("HEARD PRONUN", data); // {jibo.gl.Pronunciation}
 *   });
 *   pronounce.events.pronunciationError.on(function(data) {
 *     console.log("ERROR IN PRONUN", data);
 *   });
 *   pronounce.start();
 * }
 * ```
 * @memberof jibo.gl
 * @extends jibo.gl.ClientDialogListener
 */

        /**
         * Events for pronunciation.
         * @name jibo.gl.PronunciationListener#events
         * @type {jibo.gl.PronunciationEvents}
         */

        /**
         * Options for pronunciation.
         * @name jibo.gl.PronunciationListener#options
         * @type {jibo.gl.PronunciationOptions}
         */

   /**
    * Convenience to wrap `jibo.gl.pronounce(options, callback);`.
    * @param [word] {String} Word to pronounce
    * @param [callback] {Function} Callback with GL response.
    * @method jibo.gl.PronunciationListener#start
    * @public
    */

   /**
    * Can be called after generated-pronun event is received.
    * Collect the acoustic example of the word to be pronounced.
    * @method jibo.gl.PronunciationListener#collectExample
    * @public
    */

   /**
    * Set options to PronunciationListener.
    * @param options {jibo.gl.PronunciationOptions} Options for PronunciationListener
    * @method jibo.gl.PronunciationListener#setOptions
    * @public
    */

   /**
    * Stop PronunciationListener.
    * @param callback {Function} Callback with Global Listen response.
    * @method jibo.gl.PronunciationListener#stop
    * @public
    */